"use client";

import { useMemo } from "react";

type Props = {
  images: string[];
  unlockedCount: number; // 1..N
};

export default function ImageReveal({ images, unlockedCount }: Props) {
  const safeUnlocked = Math.max(1, Math.min(unlockedCount, images.length || 1));

  const mainSrc = useMemo(() => {
    if (!images.length) return "/images/placeholder.svg";
    return images[Math.min(safeUnlocked - 1, images.length - 1)]!;
  }, [images, safeUnlocked]);

  const steps = useMemo(() => {
    const target = Math.max(6, images.length);
    const arr: { src: string; unlocked: boolean; idx: number }[] = [];
    for (let i = 0; i < target; i++) {
      arr.push({
        src: images[i] ?? "/images/placeholder.svg",
        unlocked: i < safeUnlocked,
        idx: i,
      });
    }
    return arr;
  }, [images, safeUnlocked]);

  return (
    <section className="rounded-2xl border border-line bg-card p-4 shadow-soft">
      <div className="overflow-hidden rounded-xl border border-line bg-slate-100">
        <div className="relative aspect-[16/9] w-full">
          {/* eslint-disable-next-line @next/next/no-img-element */}
          <img src={mainSrc} alt="Clue image" className="h-full w-full object-cover" />
        </div>
      </div>

      <div className="mt-4">
        <div className="text-sm font-medium">Clue progress</div>
        <div className="mt-2 grid grid-cols-6 gap-2">
          {steps.slice(0, 6).map((s) => (
            <div
              key={s.idx}
              className={[
                "relative overflow-hidden rounded-lg border border-line bg-slate-100",
                s.unlocked ? "opacity-100" : "opacity-70",
              ].join(" ")}
            >
              <div className="aspect-[16/9]">
                {/* eslint-disable-next-line @next/next/no-img-element */}
                <img
                  src={s.src}
                  alt={`Clue ${s.idx + 1}`}
                  className={[
                    "h-full w-full object-cover",
                    s.unlocked ? "" : "blur-md grayscale",
                  ].join(" ")}
                />
              </div>
              {!s.unlocked && (
                <div className="absolute inset-0 grid place-items-center bg-white/30 text-xs font-semibold text-slate-700">
                  Locked
                </div>
              )}
            </div>
          ))}
        </div>
        <div className="mt-2 text-xs text-muted">
          Each wrong guess unlocks the next, clearer image (controlled by the <code>images</code> field in{" "}
          <code>data/games.json</code>).
        </div>
      </div>
    </section>
  );
}

